const now = new Date();
const tw = new Date(now.getTime() + 8 * 3600 * 1000);
const yyyy = tw.getUTCFullYear();
const mm = String(tw.getUTCMonth() + 1).padStart(2, '0');
const dd = String(tw.getUTCDate()).padStart(2, '0');
return [{ json: {
  isoDate: `${yyyy}-${mm}-${dd}`,
  dateSlug: `${yyyy}_${mm}_${dd}`,
  pageUrl: 'https://www.taoyuanairport.com.tw/flightforecast'
}}];

const html = $input.first().json.data || '';
const { isoDate, dateSlug } = $('計算日期').first().json;

// 找所有 href 包含 .xls 或 .xlsx 的連結
const regex = /href=["']([^"']*\.xlsx?)["']/gi;
const found = [];
let m;
while ((m = regex.exec(html)) !== null) {
  found.push(m[1]);
}

// 優先找含今日日期的連結
let xlsUrl = found.find(u => u.includes(dateSlug) || u.includes(isoDate)) || found[0] || null;

if (!xlsUrl) {
  // 如果頁面找不到，退而用猜測 URL（原始策略）
  xlsUrl = `https://www.taoyuanairport.com.tw/flightforecast/${dateSlug}.xls`;
}

// 補全相對路徑
if (xlsUrl.startsWith('/')) {
  xlsUrl = 'https://www.taoyuanairport.com.tw' + xlsUrl;
} else if (!xlsUrl.startsWith('http')) {
  xlsUrl = 'https://www.taoyuanairport.com.tw/' + xlsUrl;
}

const xlsName = xlsUrl.split('/').pop()?.split('?')[0] || `${dateSlug}.xls`;
const fileExt  = xlsUrl.toLowerCase().includes('.xlsx') ? 'xlsx' : 'xls';

console.log(`[n8n] XLS URL: ${xlsUrl} (format: ${fileExt})`);

return [{ json: { isoDate, dateSlug, xlsUrl, xlsName, fileExt } }];

const item = $input.first();
const binary = item.binary;

// ① 確認 binary 存在
if (!binary?.data) {
  throw new Error('下載失敗：未收到 Binary 資料（官網可能阻擋請求或檔案不存在）');
}

const mimeType  = (binary.data.mimeType  || '').toLowerCase();
const fileName  = (binary.data.fileName  || '').toLowerCase();
const fileSize  = binary.data.fileSize  || 0;

// ② 確認不是 HTML 錯誤頁面（通常 <5KB）
if (fileSize < 1000) {
  throw new Error(`檔案過小 (${fileSize} bytes)，可能為 HTML 錯誤頁面而非 XLS`);
}

// ③ 從 MIME 或檔名偵測格式
let detectedFormat = $('提取 XLS 下載連結').first().json.fileExt || 'xls';
if (mimeType.includes('openxmlformats') || fileName.endsWith('.xlsx')) {
  detectedFormat = 'xlsx';
} else if (mimeType.includes('ms-excel') || fileName.endsWith('.xls')) {
  detectedFormat = 'xls';
}

console.log(`[n8n] Binary OK | size=${fileSize} | mime=${mimeType} | format=${detectedFormat}`);

return [{ json: { ...item.json, detectedFormat }, binary: item.binary }];

// ─── 欄位名稱請依實際 XLS 標題調整 ──────────────────────────
const COL_HOUR   = '時段';
const COL_T1_ARR = '第一航廈入境';
const COL_T1_DEP = '第一航廈出境';
const COL_T2_ARR = '第二航廈入境';
const COL_T2_DEP = '第二航廈出境';
// ────────────────────────────────────────────────────────────

const items = $input.all();
const hours = [];

for (const item of items) {
  const row = item.json;
  const hour = parseInt(String(row[COL_HOUR]), 10);
  if (isNaN(hour) || hour < 0 || hour > 23) continue;

  hours.push({
    hour,
    forecastCount: (Number(row[COL_T1_ARR]) || 0)
                 + (Number(row[COL_T1_DEP]) || 0)
                 + (Number(row[COL_T2_ARR]) || 0)
                 + (Number(row[COL_T2_DEP]) || 0),
    terminal: 'all',
  });
}

const filled = Array.from({ length: 24 }, (_, h) =>
  hours.find(r => r.hour === h) ?? { hour: h, forecastCount: 0, terminal: 'all' }
);

const { isoDate, xlsName } = $('提取 XLS 下載連結').first().json;
return [{ json: { date: isoDate, sourceFile: xlsName, hours: filled } }];

const d = $input.first().json;
console.log(`[n8n] ✅ 寫入成功 | ${d.data?.date} | 尖峰 ${d.data?.peakHour}:00 | 總人次 ${d.data?.totalForecast}`);
return $input.all();

const d = $input.first().json;
console.error('[n8n] ❌ 寫入失敗:', JSON.stringify(d));
return $input.all();
